const HEAD_IMG=new Image(),BODY_IMG=new Image();
HEAD_IMG.src="data:image/webp;base64,";
BODY_IMG.src="data:image/webp;base64,";
function imgReady(img){ // Android Chromeのdecode()ハング対策
  return new Promise(res=>{
    if(img.complete&&img.naturalWidth>0)return res();
    img.onload=()=>res();img.onerror=()=>res();
    setTimeout(res,4000);
  });
}
// 固有選手のモチーフ画像。build.py が src/assets/signatures/<id>.png を base64 化して
// window.SIG_IMG={id:dataURI,...} を注入する(テスト時は未定義=プレースホルダ描画)。
const SIG_IMG_EL={};
if(typeof window!=="undefined"&&window.SIG_IMG){for(const k in window.SIG_IMG){const im=new Image();im.src=window.SIG_IMG[k];SIG_IMG_EL[k]=im;}}
// 汎用選手の全身図プール(window.GEN_IMG={"fw":[uri,...],...})。あれば頭部+ボディ合成より優先。
const GEN_IMG_EL={fw:[],mf:[],df:[],gk:[]};
if(typeof window!=="undefined"&&window.GEN_IMG){for(const p in window.GEN_IMG){(window.GEN_IMG[p]||[]).forEach(u=>{const im=new Image();im.src=u;(GEN_IMG_EL[p]||(GEN_IMG_EL[p]=[])).push(im);});}}
const _GEN_ALL=[].concat(...Object.values(GEN_IMG_EL));
const SPR_READY=Promise.all([imgReady(HEAD_IMG),imgReady(BODY_IMG),...Object.values(SIG_IMG_EL).map(imgReady),..._GEN_ALL.map(imgReady)]);
const withTimeout=(p,ms)=>Promise.race([p,new Promise(r=>setTimeout(r,ms))]);
const BODY_ANCHOR=[[67, 9], [74, 9], [64, 9], [49, 55], [54, 16], [66, 11], [59, 10], [74, 33], [54, 15], [66, 10], [56, 10], [64, 9], [65, 9], [65, 9], [73, 11], [75, 9]]; // 各ボディの首位置(肌色検出で算出)
const HCW=100,HCH=96,BCW=132,BCH=118,POSCOL={FW:0,MF:1,DF:2,GK:3};
// ===== ドット絵パーツ(顔=肌×髪型×髪色 / ユニフォーム(GK専用色+グローブ) / シューズ) =====
const SKIN_C=["#f5cfa0","#e3b07a","#c98850","#8d5a33"];
const HAIR_C=["#1a1a1a","#5a3517","#d9a440","#b03020","#274f9e","#cfd6dd"];
const KIT_C=[["#d32f2f","#ffffff"],["#1565c0","#ffffff"],["#2e7d32","#ffe14d"],["#6a1fa2","#ffd54f"],["#212121","#e53935"],["#fafafa","#1565c0"],["#00838f","#ffb300"]];
const GK_C=[["#fdd835","#212121"],["#ff8f00","#1a237e"],["#9ccc26","#212121"]];
const SHOE_C=["#212121","#fafafa","#d32f2f","#e8c25a"]; // 金シューズはSR専用
const POSES_BY={FW:["shoot","dribble"],MF:["pass","point"],DF:["mark","tackle"],GK:["dive","catch"]};
function makeLook(pos,rar){
  return {skin:ri(0,3),hair:ri(0,5),hc:ri(0,5),
    kit:pos==="GK"?ri(0,GK_C.length-1):ri(0,KIT_C.length-1),
    shoe:rar==="sr"?3:ri(0,2),pose:rnd(POSES_BY[pos]),
    jaw:ri(0,2),brow:ri(0,2),nose:ri(0,2),mouth:ri(0,3),beard:ri(0,3),
    headIdx:ri(0,31),bodyVar:ri(0,3)};
}
function spriteCanvas(c,hgt){ // 頭部+ボディのアトラス合成
  const W=132,H=150;
  const cv=document.createElement("canvas");cv.width=W;cv.height=H;
  cv.className="sprite";cv.style.height=hgt+"px";cv.style.width=(hgt*W/H)+"px";
  const ctx=cv.getContext("2d");ctx.imageSmoothingEnabled=true;
  if(c.sig){ // 固有選手: 頭部+ボディ合成ではなくモチーフ画像1枚を描画
    const im=SIG_IMG_EL[c.sig];
    if(im&&im.naturalWidth>0){
      const sc=Math.min(W/im.naturalWidth,H/im.naturalHeight);
      const dw=im.naturalWidth*sc,dh=im.naturalHeight*sc;
      ctx.drawImage(im,(W-dw)/2,H-dh,dw,dh); // 下端そろえで中央配置
      return cv;
    }
    // 画像未配置/未ロード: ★エンブレムのプレースホルダ
    ctx.fillStyle="#13203a";ctx.fillRect(20,18,W-40,H-36);
    ctx.fillStyle="#e8c25a";ctx.font="bold 54px serif";ctx.textAlign="center";ctx.fillText("★",W/2,H/2+4);
    ctx.fillStyle="#cfdcea";ctx.font="bold 16px sans-serif";ctx.fillText((c.name||"").slice(0,4),W/2,H-30);
    return cv;
  }
  const L=c.look||(c.look=makeLook(c.pos,c.rar));
  if(L.headIdx==null){L.headIdx=ri(0,31);L.bodyVar=ri(0,3);}
  // 全身図プールがあれば、シグネチャーと同じ等身の全身図で描画(頭部+ボディ合成より優先)
  const pool=GEN_IMG_EL[(c.pos||"FW").toLowerCase()]||[];
  if(pool.length){
    if(L.figIdx==null)L.figIdx=ri(0,pool.length-1);
    const gim=pool[L.figIdx%pool.length];
    if(gim&&gim.naturalWidth>0){
      const sc=Math.min(W/gim.naturalWidth,H/gim.naturalHeight);
      const dw=gim.naturalWidth*sc,dh=gim.naturalHeight*sc;
      ctx.drawImage(gim,(W-dw)/2,H-dh,dw,dh); // 下端そろえ中央配置(sigと同方式)
      return cv;
    }
  }
  const bi=L.bodyVar*4+POSCOL[c.pos];
  const by=H-BCH;
  try{
    if(BODY_IMG.naturalWidth===0||HEAD_IMG.naturalWidth===0)throw 0;
    ctx.drawImage(BODY_IMG,(bi%4)*BCW,(bi>>2)*BCH,BCW,BCH,0,by,BCW,BCH);
    const a=BODY_ANCHOR[bi];
    const HH=54,HW=Math.round(HH*HCW/HCH);
    ctx.drawImage(HEAD_IMG,(L.headIdx%8)*HCW,(L.headIdx>>3)*HCH,HCW,HCH,a[0]-(HW>>1),by+a[1]-HH+12,HW,HH);
  }catch(e){ // 画像が使えない端末でも簡易シルエットで続行
    const kit=(c.pos==="GK"?GK_C:KIT_C)[Math.min(L.kit,(c.pos==="GK"?GK_C:KIT_C).length-1)][0];
    ctx.fillStyle=SKIN_C[L.skin];ctx.fillRect(46,18,40,40);          // 頭
    ctx.fillStyle=HAIR_C[L.hc];ctx.fillRect(44,12,44,14);            // 髪
    ctx.fillStyle="#141a24";ctx.fillRect(56,36,6,8);ctx.fillRect(72,36,6,8); // 目
    ctx.fillStyle=kit;ctx.fillRect(46,62,40,44);                      // 胴
    ctx.fillStyle=SKIN_C[L.skin];ctx.fillRect(50,110,12,28);ctx.fillRect(70,110,12,28); // 脚
    ctx.fillStyle="#141a24";ctx.fillRect(46,138,20,8);ctx.fillRect(68,138,20,8);        // 靴
  }
  return cv;
}
