const rnd=a=>a[Math.floor(Math.random()*a.length)];
const ri=(a,b)=>a+Math.floor(Math.random()*(b-a+1));
// 決定的PRNG(mulberry32)で Math.random を一時的に差し替え、restore() で元に戻す。
// oppTeam の生成中だけ使うことで「同じ seed → 同じロスター」を実現(生成ロジックは不変=強さ不変)。
function seedRandom(seed){
  const orig=Math.random; let s=seed>>>0;
  Math.random=function(){
    s=s+0x6D2B79F5|0;
    let t=Math.imul(s^s>>>15,1|s);
    t=t+Math.imul(t^t>>>7,61|t)^t;
    return ((t^t>>>14)>>>0)/4294967296;
  };
  return ()=>{Math.random=orig;};
}
const cl=v=>Math.min(20,Math.max(1,v));
const RAR_TOTAL={l:98,sr:88,r:68,n:53}; // 6ステータス合計の目標(丸め上振れ込みで実測≒100/90/70/55)
// 目標合計付近になるよう6値を生成(分散を持たせてから正規化し1-20にクランプ)
function genStats(rar){
  const total=RAR_TOTAL[rar]||55;
  let v=[0,0,0,0,0,0].map(()=>1+Math.random());  // 1.0〜2.0の素の重み
  let sum=v.reduce((a,b)=>a+b,0);
  v=v.map(x=>x/sum*total);                         // 合計=totalにスケール
  // 1〜20にクランプしつつ、はみ出し分を他へ再配分
  for(let iter=0;iter<6;iter++){
    v=v.map(x=>Math.min(20,Math.max(1,x)));
    const diff=total-v.reduce((a,b)=>a+b,0);
    if(Math.abs(diff)<0.5)break;
    const room=v.map(x=>diff>0?20-x:x-1);
    const rt=room.reduce((a,b)=>a+b,0)||1;
    v=v.map((x,i)=>x+diff*room[i]/rt);
  }
  return v.map(x=>Math.round(Math.min(20,Math.max(1,x))));
}
function scaleTo(c,target){ // 既存6ステの合計をtargetへ比例スケール(1-20クランプ)
  const ks=["off","def","pow","tec","spd","sta"];
  let cur=ks.reduce((s,k)=>s+c[k],0);
  if(cur<=0)return;
  let f=target/cur;
  ks.forEach(k=>c[k]=Math.round(Math.min(20,Math.max(1,c[k]*f))));
}

let uid=1;
function rollSkill(pos,rar){
  if(rar==="n")return null;
  if(rar==="l"){const [name,desc,fx]=rnd(LSKILLS[pos]);return {name,desc,fx};}
  const [name,desc,fx]=rnd(SKILLS[pos][rar]);
  return {name,desc,fx};
}
function makeCard(forcePos,forceRar,forceBase,forceSub){
  // forcePos は大分類(GK/DF/MF/FW)。細分pos(CF/LSB等)が来たら大分類へ正規化し、細分として採用。
  if(forcePos&&SUBS_BY[forcePos]==null&&SUBGROUP[forcePos]){forceSub=forceSub||forcePos;forcePos=SUBGROUP[forcePos];}
  const pos=forcePos||rnd(["GK","DF","DF","MF","MF","MF","FW","FW"]);
  const sub=(forceSub&&SUBGROUP[forceSub]===pos)?forceSub:rnd(SUBS_BY[pos]);
  let rar=forceRar;
  if(!rar){const x=Math.random()*100;rar=x<5?"sr":x<30?"r":"n";}
  const sv=genStats(rar);
  const c={id:uid++,name:rnd(NAMES),flag:rnd(FLAGS),look:makeLook(pos,rar),pos,sub,rar,type:rollType(pos),
    off:sv[0],def:sv[1],pow:sv[2],tec:sv[3],spd:sv[4],sta:sv[5],skill:rollSkill(pos,rar)};
  if(pos==="GK"){c.def=cl(c.def+3);c.off=cl(c.off-3);}
  if(pos==="DF"){c.def=cl(c.def+2);c.pow=cl(c.pow+1);c.off=cl(c.off-2);}
  if(pos==="MF"){c.tec=cl(c.tec+2);c.sta=cl(c.sta+1);}
  if(pos==="FW"){c.off=cl(c.off+2);c.spd=cl(c.spd+1);c.def=cl(c.def-2);}
  return c;
}

